import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable Apple Ads","description":"","frontmatter":{"title":"Enable Apple Ads","slug":"enable-apple-ads"},"headers":[],"relativePath":"marketer-hub/enable-apple-ads.md","filePath":"marketer-hub/enable-apple-ads.md"}'),r={name:"marketer-hub/enable-apple-ads.md"};function n(s,e,l,d,p,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To enable Apple Ads, you first need to:</p><ol><li>Create a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Enable Ads for your Branch account. Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a>.</li><li>Have a mobile developer prepared to implement the Apple Ads token.</li><li>Have admin access to your Apple Ads account.</li></ol><h2 id="enable-apple-ads" tabindex="-1">Enable Apple Ads <a class="header-anchor" href="#enable-apple-ads" aria-label="Permalink to &quot;Enable Apple Ads&quot;">​</a></h2><h3 id="_1-configure-token" tabindex="-1">1. Configure token <a class="header-anchor" href="#_1-configure-token" aria-label="Permalink to &quot;1. Configure token&quot;">​</a></h3><p>You have to choose <strong>one</strong> of the following options for retrieving the Apple Ads Token to get started with enabling Apple Ads with Branch:</p><ul><li>via SDK <strong>or</strong></li><li>via Server-to-Server (S2S)</li></ul><p>For more information on configuring the Apple Ads Token, please visit our <a href="./configure-apple-ads-token.html">developer documentation</a>.</p><h3 id="_2-connect-apple-ads-in-branch" tabindex="-1">2. Connect Apple Ads in Branch <a class="header-anchor" href="#_2-connect-apple-ads-in-branch" aria-label="Permalink to &quot;2. Connect Apple Ads in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt; Partner Management</strong>, find/search for Apple Ads or click <a href="https://dashboard.branch.io/ads/partner-management/a_apple?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Click the <strong>Sign in With Apple</strong> button to complete authentication. You&#39;ll also be able to select your organization here.</p><p>Click the <strong>Save &amp; Enable</strong> button after authentication.</p><p>Afterward, you should see a successful integration status:</p><h3 id="_3-configure-attribution-windows" tabindex="-1">3. Configure attribution windows <a class="header-anchor" href="#_3-configure-attribution-windows" aria-label="Permalink to &quot;3. Configure attribution windows&quot;">​</a></h3><p>After authenticating your Apple Ads account with Branch, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_apple?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows tab</strong></a> to set windows by attribution type.</p><p>You have full freedom to choose your attribution windows; however, it may cause discrepancies between Branch and Apple Ads when comparing data if you don’t use the recommended windows.</p><table tabindex="0"><thead><tr><th>Attribution type</th><th>Apple’s recommended attribution window</th></tr></thead><tbody><tr><td>click to session start</td><td>1 day</td></tr><tr><td>click to install</td><td>7 days</td></tr><tr><td>click to conversion event</td><td>30 days</td></tr></tbody></table><h3 id="_4-launch-apple-ads-campaigns" tabindex="-1">4. Launch Apple Ads campaigns <a class="header-anchor" href="#_4-launch-apple-ads-campaigns" aria-label="Permalink to &quot;4. Launch Apple Ads campaigns&quot;">​</a></h3><p>You&#39;ve now completed the setup steps! Now you can start running campaigns to see data flowing into Branch.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>If an Agency manages your Apple Ads campaigns, please see <a href="./what-is-a-self-attributing-network.html#agency-managed-san-campaigns">Agency-managed SAN Campaigns</a>.</p></div><h3 id="_5-verify-data-in-branch" tabindex="-1">5. Verify data in Branch <a class="header-anchor" href="#_5-verify-data-in-branch" aria-label="Permalink to &quot;5. Verify data in Branch&quot;">​</a></h3><p>You can go to the <a href="https://dashboard.branch.io/ads/analytics/activity" target="_blank" rel="noreferrer"><strong>Ads Analytics page</strong></a> to view your Apple Ads performance in the Branch Dashboard.</p><p>All performance registered from Apple Ads will automatically be tagged with the <code>Channel: Apple App Store</code> and the <code>Ad Partner: Apple Ads</code>. The campaign will be set to the <code>Campaign Name</code> you&#39;ve configured in the Apple Ads dashboard.</p><div class="info custom-block"><p class="custom-block-title">Info</p><p>For more details on Apple Ads reporting and analytics, view our guide <a href="./apple-search-ads-data-reporting.html">here</a>.</p></div><h2 id="apple-privacy-frameworks" tabindex="-1">Apple privacy frameworks <a class="header-anchor" href="#apple-privacy-frameworks" aria-label="Permalink to &quot;Apple privacy frameworks&quot;">​</a></h2><h3 id="skadnetwork" tabindex="-1">SKAdNetwork <a class="header-anchor" href="#skadnetwork" aria-label="Permalink to &quot;SKAdNetwork&quot;">​</a></h3><p>Apple Ads supports SKAdNetwork (SKAN) attribution tracking for <strong>SKAN versions 1.0, 2.0, and 3.0 only</strong>.</p><p>Using Apple Ads with SKAN helps you better understand how users discover and download your iOS app through Apple&#39;s advertising platform.</p><p>If you enable SKAN attribution tracking with Apple Ads, you&#39;ll get better insights into how users find your app through:</p><ul><li>App Store search results</li><li>App Store Today tab</li><li>App Store Search tab</li><li>App Store product pages</li></ul><p>If you want to access this new attribution data, you first need to:</p><ol><li>Enable SKAN direct postbacks.</li><li>Have your technical team implement a simple app update.</li></ol><h3 id="ad-attribution-kit" tabindex="-1">Ad Attribution Kit <a class="header-anchor" href="#ad-attribution-kit" aria-label="Permalink to &quot;Ad Attribution Kit&quot;">​</a></h3><p>Ad Attribution Kit (AAK) is Apple’s attribution framework that succeeds SKAN. Branch supports AAK for Apple Ads campaigns.</p><h4 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h4><p>To use AAK with Branch for Apple Ads attribution, you must add AAK configuration to your app’s Info.plist file in addition to your existing SKAdNetwork entries. Follow <a href="https://developer.apple.com/documentation/adattributionkit/configuring-an-advertised-app" target="_blank" rel="noreferrer">Apple’s AAK configuration guide</a> for more details.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Apps without AAK configuration will <strong>experience attribution interruption for Apple Ads as users upgrade to iOS versions 26.2+</strong>.</p></div><h2 id="data-mappings" tabindex="-1">Data mappings <a class="header-anchor" href="#data-mappings" aria-label="Permalink to &quot;Data mappings&quot;">​</a></h2><p>The table in this section details how Branch maps Apple Ads fields to Branch fields.</p><p>Additional notes about the columns:</p><ul><li><code>body_campaign_id</code>: Apple will only send Branch 4 possible values for this field.</li><li><code>last_attributed_touch_data_tilde_campaign</code>: Branch takes <code>body_campaign_id</code> and maps it to this field.</li><li><strong>Touch type</strong>: The value for this field will alway be “Taps” (clicks).</li><li><code>body_fidelity_type</code>: Branch reflects the touch type in this field, using the value 1 to indicate clicks.</li></ul><table tabindex="0"><thead><tr><th><code>body_campaign_id</code></th><th><code>last_attributed_touch_data_tilde_campaign</code></th><th>Touch type</th><th><code>body_fidelity_type</code></th></tr></thead><tbody><tr><td>10</td><td>APPSTORE_SEARCH_RESULTS</td><td>Taps</td><td>1</td></tr><tr><td>20</td><td>APPSTORE_TODAY_TAB</td><td>Taps</td><td>1</td></tr><tr><td>30</td><td>APPSTORE_SEARCH_TAB</td><td>Taps</td><td>1</td></tr><tr><td>40</td><td>APPSTORE_PRODUCT_PAGES_BROWSE</td><td>Taps</td><td>1</td></tr></tbody></table><h2 id="advanced-steps-and-troubleshooting" tabindex="-1">Advanced steps and troubleshooting <a class="header-anchor" href="#advanced-steps-and-troubleshooting" aria-label="Permalink to &quot;Advanced steps and troubleshooting&quot;">​</a></h2><details><summary>Install discrepancies when compared with Apple Ads dashboard</summary><p>There are a few possible causes of discrepancies with Apple Ads. Due to the low customizability of Apple Ads&#39; attribution settings, discrepancies are often higher on Apple Ads than other platforms, even though performance may be solid and reporting may be working as expected. The best way to attempt reconciliation with Apple Ads installs and Branch is to look at &#39;New Download&#39; counts, but subtract the percentage of LAT on users found by grouping LAT on/off in reporting. This will give an estimate of new downloads with LAT off, while Branch reports first opens from those downloads.</p><ul><li><strong>Time zones</strong> - Ensure your Apple Ads time zone (in Settings &gt; Overview &gt; Account Information ) matches your Branch Dashboard time zone (visible under Account Settings).</li><li><strong>Limit Ad Tracking (LAT) On</strong> - Apple Ads doesn&#39;t report installs to third parties if the user has Limit Ad Tracking. However, the Apple Ads dashboard shows all installs by default, regardless of limit ad tracking state. If the newer framework is properly set up, attribution will still be provided for LAT-on or ATT opted-out users and this will not be a source of discrepancy, but if the new framework is not set up properly this may still cause a difference in numbers.</li><li><strong>Attribution Windows</strong> - Apple Ads attributes all installs within 30 days of an Apple Ads click to itself. Branch&#39;s default click to install attribution window is 7 days. You can modify Branch&#39;s click to install window. You can modify your Apple Ads attribution windows in Branch.</li><li><strong>Last-click attribution</strong> - Apple Ads attributes all installs within 30 days of an Apple Ads click to itself. Branch will attribute to the last click within its attribution windows, which can often be a different source than Apple Ads.</li><li><strong>Reinstalls</strong> - Apple Ads&#39; dashboard shows reinstalls as conversions in its default view, but Branch calls these installs &quot;REINSTALLS.&quot; In the Apple dashboard, select New Downloads or Redownloads in the column selector to align data.</li><li><strong>Attribution API timeouts or delays</strong> - Apple Ads Attribution API can be slow to respond. Although customers can edit the timeout, the default Branch timeout in the code above is just over 1 second. If Apple Ads responds after this timeout, Branch will not attribute the install to Apple Ads.</li><li><strong>Opens vs. installs</strong> - Branch considers the first open to be the install. Apple Ads considers the time that the user downloaded the app to be an install. This can cause discrepancies in counts and date of install.</li></ul></details><details><summary>Adding deep linking to Apple Ads</summary><p>Since this integration doesn&#39;t utilize Branch Links, options for deep linking are limited. We&#39;ll pass back the value you use for <code>campaign</code> in the Apple Ads dashboard. Since this value is controlled by you, you can put anything there, but it will reflect on the Branch dashboard. We will track installs regularly.<br> You can retrieve this parameter in the app to be used for <a href="./ios-advanced-features.html#general-deep-linking">deep linking</a>.</p></details><details><summary>Installs or conversion events appearing without keywords in Branch Dashboard</summary><p>There are Keyword and Search Match match sources for Apple Ads. The Search Match feature automatically matches your ad to relevant user searches on the App Store, rather than a rubric of preassigned keywords. Installs attributed to Search Matches do not have keywords associated with them. Search Match can be enabled &amp; disabled at the Ad Group level in the Apple Ads dashboard.</p></details><details><summary>Using TestFlight app or Developer App</summary><p>If you are using the new Apple Ads framework and are debugging or testing your app using the TestFlight app or developer app, Apple Ads returns dummy values of test campaign data with Campaign ID as <code>1234567890</code> which will be visible in the Branch Dashboard. Please ensure to filter it out when looking at your Apple Ads attributed campaign data in the Dashboard.</p></details><details><summary>Re-Authentication</summary><p>If you ever need to restart your integration with Apple Ads, you must do so by clicking the Reset Settings cog button in the Apple Ads settings in the <a href="https://dashboard.branch.io/ads/partner-management/a_apple?tab=settings" target="_blank" rel="noreferrer">Branch Dashboard</a>. Clicking the Disable button at the bottom will not reset your integration.</p></details>',48)])])}const A=t(r,[["render",n]]);export{u as __pageData,A as default};
